9	} from 'react';
10	
11	/**
12	 * AppShell — the canonical layout grid for the BIM AI workspace.
13	 *
14	 * Responsibilities (spec §8):
15	 *   - Five-zone CSS grid: topbar (48 px) / left rail / canvas / right rail
16	 *     / status bar (28 px).
17	 *   - Three documented breakpoints driven by tokens: `>= 1600` (full
18	 *     rails), `1280–1599` (slim rails), `1024–1279` (left rail collapses
19	 *     to a 56 px icon strip), `< 1024` (rails become overlays toggled by
20	 *     `[` / `]`).
21	 *   - Keyboard hotkeys: `[` toggles left rail collapsed-vs-expanded; `]`
22	 *     toggles right rail.
23	 *
24	 * Slot props are pure render functions. AppShell does not own canvas /
25	 * rail content — composed surfaces (TopBar, ProjectBrowser, Inspector,
26	 * StatusBar) are wired in by their owning workpackages (A03–A06).
27	 */
28	
29	export interface AppShellProps {
30	  topBar: ReactNode;
31	  leftRail: ReactNode;
32	  /** Compact contents shown when the left rail is collapsed (icon-strip). */
33	  leftRailCollapsed?: ReactNode;
34	  canvas: ReactNode;
35	  rightRail: ReactNode;
36	  statusBar: ReactNode;
37	  /** Initial collapsed state for the left rail. Defaults to false. */
38	  defaultLeftCollapsed?: boolean;
39	  /** Initial collapsed state for the right rail. Defaults to false. */
40	  defaultRightCollapsed?: boolean;
41	  /** Override the document target for the global `[` / `]` hotkeys.
42	   * Used by tests to scope the listeners. */
43	  hotkeyTarget?: Document | HTMLElement;
44	}
45	
46	export function AppShell({
47	  topBar,
48	  leftRail,
49	  leftRailCollapsed,
50	  canvas,
51	  rightRail,
52	  statusBar,
53	  defaultLeftCollapsed = false,
54	  defaultRightCollapsed = false,
55	  hotkeyTarget,
56	}: AppShellProps): JSX.Element {
57	  const [leftCollapsed, setLeftCollapsed] = useState(defaultLeftCollapsed);
58	  const [rightCollapsed, setRightCollapsed] = useState(defaultRightCollapsed);
59	
60	  const handleKey = useCallback((event: KeyboardEvent | globalThis.KeyboardEvent) => {
61	    if (shouldIgnoreKey(event)) return;
62	    if (event.key === '[') {
63	      event.preventDefault();
64	      setLeftCollapsed((v) => !v);
65	    } else if (event.key === ']') {
66	      event.preventDefault();
67	      setRightCollapsed((v) => !v);
68	    }
69	  }, []);
70	
71	  useEffect(() => {
72	    const target: Document | HTMLElement | undefined =
73	      hotkeyTarget ?? (typeof document !== 'undefined' ? document : undefined);
74	    if (!target) return;
75	    const listener = (e: globalThis.KeyboardEvent): void => handleKey(e);
76	    target.addEventListener('keydown', listener as EventListener);
77	    return () => target.removeEventListener('keydown', listener as EventListener);
78	  }, [handleKey, hotkeyTarget]);
79	
80	  const style: CSSProperties = {
81	    display: 'grid',
82	    gridTemplateRows: 'auto minmax(0, 1fr) var(--shell-statusbar-height)',
83	    gridTemplateColumns: gridColumnsForState(leftCollapsed, rightCollapsed),
84	    gridTemplateAreas: `
85	      "topbar topbar topbar"
86	      "leftRail canvas rightRail"
87	      "statusbar statusbar statusbar"
88	    `,
89	    minHeight: '100vh',
90	    width: '100%',
91	    background: 'var(--color-background)',
92	    color: 'var(--color-foreground)',
93	  };
94	
95	  return (
96	    <div
97	      data-testid="app-shell"
98	      data-left-collapsed={leftCollapsed ? 'true' : 'false'}
99	      data-right-collapsed={rightCollapsed ? 'true' : 'false'}
100	      style={style}
101	    >
102	      <div
103	        style={{ gridArea: 'topbar' }}
104	        className="flex items-center border-b border-border bg-surface"
105	      >
106	        {topBar}
107	      </div>
108	      <aside
109	        aria-label="Project browser"
110	        data-testid="app-shell-left-rail"
111	        style={{ gridArea: 'leftRail', minWidth: 0 }}
112	        className="flex flex-col border-r border-border bg-surface"
113	      >
114	        {leftCollapsed ? (leftRailCollapsed ?? null) : leftRail}
115	      </aside>
116	      <main
117	        aria-label="Canvas"
118	        data-testid="app-shell-canvas"
119	        style={{ gridArea: 'canvas', minWidth: 0, minHeight: 0 }}
120	        className="relative overflow-hidden bg-background"
121	      >
122	        {canvas}
123	      </main>
124	      <aside
125	        aria-label="Inspector"
126	        data-testid="app-shell-right-rail"
127	        style={{ gridArea: 'rightRail', minWidth: 0 }}
128	        className="flex flex-col border-l border-border bg-surface"
129	        hidden={rightCollapsed}
130	      >
131	        {rightRail}
132	      </aside>
133	      <footer
134	        style={{ gridArea: 'statusbar' }}
135	        className="flex items-center border-t border-border bg-surface text-xs"
136	      >
137	        {statusBar}
138	      </footer>
139	    </div>
140	  );
141	}
142	
143	function gridColumnsForState(leftCollapsed: boolean, rightCollapsed: boolean): string {
144	  const left = leftCollapsed
145	    ? 'var(--shell-rail-left-collapsed-width)'
146	    : 'var(--shell-rail-left-width)';
147	  const right = rightCollapsed ? '0' : 'var(--shell-rail-right-width)';
148	  return `${left} minmax(0, 1fr) ${right}`;
149	}
150	
151	function shouldIgnoreKey(event: KeyboardEvent | globalThis.KeyboardEvent): boolean {
152	  const target = event.target as HTMLElement | null;
153	  if (!target) return false;
154	  if (event.metaKey || event.ctrlKey || event.altKey) return true;
155	  const tag = target.tagName;
156	  if (tag === 'INPUT' || tag === 'TEXTAREA' || tag === 'SELECT') return true;
157	  if (target.isContentEditable) return true;
