```ts
// Orbit inertia: continue rotating after mouse release, decaying to stop
if (!dragging && Math.hypot(inertiaVx, inertiaVy) > 0.06) {
  rig.orbit(inertiaVx, inertiaVy);
  inertiaVx *= INERTIA_DECAY;
  inertiaVy *= INERTIA_DECAY;
  placeCamera();
}
```

